24	// Process a 'concurrent assertion'
25	//
26	// Any top level clocking expressions have been stripped. Clocking is part
27	// of the created procedural context.
28	void process_sva_property(const ast::ConcurrentAssertionStatement &statement,
29							  const ast::StatementBlockSymbol *block,
30							  ProceduralContext &procedural, const ast::AssertionExpr &top_expr)
31	{
32		auto &netlist = procedural.netlist;
33	
34		const ast::AssertionExpr *expr = &top_expr;
35		slang::SourceRange source_range = expr->syntax ? expr->syntax->sourceRange() : statement.sourceRange;
36	
37		// Extract disable iff condition if present; the extracted switch
38		// needs to live until the end of the function to be picked up
39		// by set_effects_trigger
40		std::optional<SwitchHelper> switch_;
41		auto guard = slang::ScopeGuard([&] {
42			if (switch_.has_value()) {
43				switch_->exit_branch();
44				switch_->finish(netlist);
45			}
46		});
47		if (ast::DisableIffAssertionExpr::isKind(expr->kind)) {
48			auto &disable = expr->as<ast::DisableIffAssertionExpr>();
49			switch_.emplace(procedural, netlist.ReduceBool(procedural.eval.sva(disable.condition)));
50			switch_->enter_branch({RTLIL::S0});
51			expr = &disable.expr;
52			source_range = expr->syntax ? expr->syntax->sourceRange() : statement.sourceRange;
53		}
54	
55		if (!ast::SimpleAssertionExpr::isKind(expr->kind)) {
56			netlist.add_diag(diag::UnsupportedSVAFeature, source_range);
57			return;
58		}
59	
60		auto &simple_assertion = expr->as<ast::SimpleAssertionExpr>();
61	
62		// We don't support repetition in simple assertions
63		if (simple_assertion.repetition.has_value()) {
64			netlist.add_diag(diag::RepetitionsUnsupported, source_range);
65			return;
66		}
67	
68		std::string flavor;
69		switch (statement.assertionKind) {
70		case ast::AssertionKind::Assert:        flavor = "assert"; break;
71		case ast::AssertionKind::Assume:        flavor = "assume"; break;
72		case ast::AssertionKind::CoverProperty: flavor = "cover"; break;
73		default:                                netlist.add_diag(diag::AssertionUnsupported, statement.sourceRange); return;
74		}
75	
76		RTLIL::IdString cell_name;
77	
78		if (block && unwrap_statement(block->tryGetStatement()) == &statement && !block->name.empty()) {
79			// If we are the sole statement in a block, use the block's label
80			cell_name = netlist.id(*block);
81		} else {
82			cell_name = netlist.new_id();
83		}
84	
85		RTLIL::SigSpec a = netlist.ReduceBool(procedural.eval.sva(simple_assertion.expr));
86	
87		auto cell = netlist.canvas->addCell(cell_name, ID($check));
88		procedural.set_effects_trigger(cell);
89		cell->setParam(ID::FLAVOR, flavor);
90		cell->setParam(ID::FORMAT, std::string(""));
91		cell->setParam(ID::ARGS_WIDTH, 0);
92		cell->setParam(ID::PRIORITY, --procedural.effects_priority);
93		cell->setPort(ID::ARGS, {});
94		cell->setPort(ID::A, a);
95		transfer_attrs<const ast::Statement>(netlist, statement, cell);
96	}
97	
98	void process_freestanding_sva_property(NetlistContext &netlist,
99										   const ast::ConcurrentAssertionStatement &statement,
100							  			   const ast::StatementBlockSymbol *block)
101	{
102		const ast::AssertionExpr &spec = statement.propertySpec;
103	
104		if (ast::ClockingAssertionExpr::isKind(spec.kind)) {
105			// Need to strip clocking
106			const auto &clocking_expr = spec.as<ast::ClockingAssertionExpr>();
107			const auto &clocking = clocking_expr.clocking;
108	
109			if (!ast::SignalEventControl::isKind(clocking.kind)) {
110				netlist.add_diag(diag::UnsupportedSVAFeature, clocking.sourceRange);
111				return;
112			}
113	
114			const auto &signal_event = clocking.as<ast::SignalEventControl>();
115	
116			ProcessTiming timing(ProcessTiming::EdgeTriggered);
117			switch (signal_event.edge) {
118			case ast::EdgeKind::None:
119				netlist.add_diag(diag::SVAClockingRequiresEdge, signal_event.sourceRange);
120				return;
121	
122			case ast::EdgeKind::PosEdge:
123			case ast::EdgeKind::NegEdge:
124				timing.triggers.push_back(ProcessTiming::Sensitivity {
125					.signal = netlist.eval(signal_event.expr),
126					.edge_polarity = (signal_event.edge == ast::EdgeKind::PosEdge),
127					.ast_node = &clocking
128				});
129				break;
130	
131			case ast::EdgeKind::BothEdges:
132				netlist.add_diag(diag::BothEdgesUnsupported, signal_event.sourceRange);
133				return;
134			}
135	
136			if (signal_event.iffCondition) {
137				// TODO
138				netlist.add_diag(diag::IffUnsupported, signal_event.iffCondition->sourceRange);
139			}
140	
141			ProceduralContext procedure(netlist, timing);
142			process_sva_property(statement, block, procedure, clocking_expr.expr);
143	
144			RTLIL::Process *rtlil_proc = netlist.canvas->addProcess(netlist.new_id());
145			transfer_attrs<const ast::Statement>(netlist, statement, rtlil_proc);
146			procedure.copy_case_tree_into(rtlil_proc->root_case);
147		} else {
148			// No clocking
149			ProceduralContext procedure(netlist, ProcessTiming::implicit);
150			process_sva_property(statement, block, procedure, spec);
151	
152			RTLIL::Process *rtlil_proc = netlist.canvas->addProcess(netlist.new_id());
153			transfer_attrs<const ast::Statement>(netlist, statement, rtlil_proc);
154			procedure.copy_case_tree_into(rtlil_proc->root_case);
155		}
156	}
157	
158	};
